glM(){return"\u0412 \u0441\u0442\u043e\u043b\u0431\u0446\u0435"},
glL(){return"\u0414\u0432\u0435 \u044f\u0447\u0435\u0439\u043a\u0438 \u0432 \u0441\u0442\u043e\u043b\u0431\u0446\u0435 8 \u0438\u043c\u0435\u044e\u0442 \u0440\u043e\u0432\u043d\u043e \u043e\u0434\u043d\u0438 \u0438 \u0442\u0435 \u0436\u0435 \u0434\u0432\u0430 \u043a\u0430\u043d\u0434\u0438\u0434\u0430\u0442\u0430: [1, 2]. \u041f\u043e\u0441\u043a\u043e\u043b\u044c\u043a\u0443 \u044d\u0442\u0438 \u0434\u0432\u0435 \u0446\u0438\u0444\u0440\u044b \u0434\u043e\u043b\u0436\u043d\u044b \u0441\u0442\u043e\u044f\u0442\u044c \u0432 \u044d\u0442\u0438\u0445 \u0434\u0432\u0443\u0445 \u044f\u0447\u0435\u0439\u043a\u0430\u0445, \u0432 \u043b\u044e\u0431\u043e\u0439 \u0434\u0440\u0443\u0433\u043e\u0439 \u044f\u0447\u0435\u0439\u043a\u0435 \u0441\u0442\u043e\u043b\u0431\u0446\u0430 8 \u043a\u0430\u043d\u0434\u0438\u0434\u0430\u0442\u043e\u0432 1 \u0438\u043b\u0438 2 \u043c\u043e\u0436\u043d\u043e \u0438\u0441\u043a\u043b\u044e\u0447\u0438\u0442\u044c."},
