gmG(){return"\u0413\u043e\u043b\u044b\u0439 \u043e\u0434\u0438\u043d\u043e\u0447\u043a\u0430 \u2014 \u0431\u043b\u043e\u043a"},
gmF(){return"\u0411\u043b\u043e\u043a"},
gmE(){return"\u041f\u043e\u0441\u043c\u043e\u0442\u0440\u0438\u0442\u0435 \u043d\u0430 \u0431\u043b\u043e\u043a 2\xd73. \u0412 \u043e\u0434\u043d\u043e\u0439 \u043f\u0443\u0441\u0442\u043e\u0439 \u044f\u0447\u0435\u0439\u043a\u0435 \u043d\u0435 \u0445\u0432\u0430\u0442\u0430\u0435\u0442 \u0442\u043e\u043b\u044c\u043a\u043e \u043e\u0434\u043d\u043e\u0439 \u0446\u0438\u0444\u0440\u044b \u2014 \u0432\u0441\u0435 \u043e\u0441\u0442\u0430\u043b\u044c\u043d\u044b\u0435 \u0437\u043d\u0430\u0447\u0435\u043d\u0438\u044f \u0443\u0436\u0435 \u0435\u0441\u0442\u044c \u0432 \u0431\u043b\u043e\u043a\u0435, \u0441\u0442\u0440\u043e\u043a\u0435 \u0438\u043b\u0438 \u0441\u0442\u043e\u043b\u0431\u0446\u0435. \u041f\u043e\u0441\u0442\u0430\u0432\u044c\u0442\u0435 \u0435\u0451."},
gmD(){return"\u0413\u043e\u043b\u044b\u0439 \u043e\u0434\u0438\u043d\u043e\u0447\u043a\u0430 \u0432 R5C5 \u2014 \u0432\u043e\u0437\u043c\u043e\u0436\u043d\u0430 \u0442\u043e\u043b\u044c\u043a\u043e 2"},
gma(){return"\u0421\u043a\u0440\u044b\u0442\u044b\u0439 \u043e\u0434\u0438\u043d\u043e\u0447\u043a\u0430 \u2014 \u0441\u0442\u0440\u043e\u043a\u0430"},
gm9(){return"\u0421\u0442\u0440\u043e\u043a\u0430"},
gm8(){return"\u0412 \u0432\u0435\u0440\u0445\u043d\u0435\u0439 \u0441\u0442\u0440\u043e\u043a\u0435 \u0446\u0438\u0444\u0440\u0430 3 \u043c\u043e\u0436\u0435\u0442 \u043f\u043e\u043c\u0435\u0441\u0442\u0438\u0442\u044c\u0441\u044f \u0442\u043e\u043b\u044c\u043a\u043e \u0432 \u043e\u0434\u043d\u0443 \u044f\u0447\u0435\u0439\u043a\u0443 \u2014 \u0434\u0430\u0436\u0435 \u0435\u0441\u043b\u0438 \u0432 \u044d\u0442\u043e\u0439 \u044f\u0447\u0435\u0439\u043a\u0435 \u0435\u0441\u0442\u044c \u0434\u0440\u0443\u0433\u0438\u0435 \u043a\u0430\u043d\u0434\u0438\u0434\u0430\u0442\u044b. \u041f\u0440\u043e\u0441\u043c\u043e\u0442\u0440\u0438\u0442\u0435 \u0441\u0442\u0440\u043e\u043a\u0443: \u0433\u0434\u0435 \u0435\u0434\u0438\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0435 \u043c\u0435\u0441\u0442\u043e, \u043a\u0443\u0434\u0430 \u043c\u043e\u0436\u0435\u0442 \u043f\u043e\u0439\u0442\u0438 3?"},
gm7(){return"\u0421\u043a\u0440\u044b\u0442\u044b\u0439 \u043e\u0434\u0438\u043d\u043e\u0447\u043a\u0430 \u0432 R1C2 \u2014 3 \u043c\u043e\u0436\u0435\u0442 \u0441\u0442\u043e\u044f\u0442\u044c \u0442\u043e\u043b\u044c\u043a\u043e \u0437\u0434\u0435\u0441\u044c \u0432 \u0441\u0442\u0440\u043e\u043a\u0435 1"},
gme(){return"\u0421\u043a\u0440\u044b\u0442\u044b\u0439 \u043e\u0434\u0438\u043d\u043e\u0447\u043a\u0430 \u2014 \u0441\u0442\u043e\u043b\u0431\u0435\u0446"},
gmd(){return"\u0421\u0442\u043e\u043b\u0431\u0435\u0446"},
gmc(){return"\u041f\u0440\u043e\u0441\u043c\u043e\u0442\u0440\u0438\u0442\u0435 \u044d\u0442\u043e\u0442 \u0441\u0442\u043e\u043b\u0431\u0435\u0446 \u0432 \u043f\u043e\u0438\u0441\u043a\u0430\u0445 \u0446\u0438\u0444\u0440\u044b 6. \u041d\u0435\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u044f\u0447\u0435\u0435\u043a \u043f\u0443\u0441\u0442\u044b, \u043d\u043e 6 \u043f\u043e\u043c\u0435\u0449\u0430\u0435\u0442\u0441\u044f \u0442\u043e\u043b\u044c\u043a\u043e \u0432 \u043e\u0434\u043d\u0443 \u0438\u0437 \u043d\u0438\u0445 \u2014 \u043e\u0441\u0442\u0430\u043b\u044c\u043d\u044b\u0435 \u0437\u0430\u0431\u043b\u043e\u043a\u0438\u0440\u043e\u0432\u0430\u043d\u044b \u0441\u0432\u043e\u0438\u043c\u0438 \u0441\u0442\u0440\u043e\u043a\u0430\u043c\u0438 \u0438\u043b\u0438 \u0431\u043b\u043e\u043a\u0430\u043c\u0438."},
gmb(){return"\u0421\u043a\u0440\u044b\u0442\u044b\u0439 \u043e\u0434\u0438\u043d\u043e\u0447\u043a\u0430 \u0432 R2C2 \u2014 6 \u043c\u043e\u0436\u0435\u0442 \u0441\u0442\u043e\u044f\u0442\u044c \u0442\u043e\u043b\u044c\u043a\u043e \u0437\u0434\u0435\u0441\u044c \u0432 \u0441\u0442\u043e\u043b\u0431\u0446\u0435 2"},
